#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;
const double eps=1e-8;

struct Node{
    double A,B,R,a,b,x,y;
    int id;
}p[N],t[N];

bool cmp(Node x,Node y){
    return x.A*y.B<y.A*x.B;
}

int n,s,q[N],hh,tt;
double f[N];

double slope(int x,int y){
    if(fabs(p[x].x-p[y].x)<=eps)
        return 1e18;
    return (p[x].y-p[y].y)/(p[x].x-p[y].x);
}

void solve(int l,int r){
    if(l==r){
        f[l]=max(f[l],f[l-1]);
        p[l].x=f[l]/p[l].a;
        p[l].y=-f[l]/p[l].b;
        return;
    }
    int mid=l+r>>1;
    for(int i=l,j=l,k=mid+1;i<=r;i++)
        if(p[i].id<=mid)
            t[j]=p[i],j++;
        else
            t[k]=p[i],k++;
    for(int i=l;i<=r;i++)
        p[i]=t[i];
    solve(l,mid);
    hh=1,tt=0;
    for(int i=l;i<=mid;i++){
        while(hh<tt && slope(q[tt-1],q[tt])>slope(q[tt],i)-eps)
            tt--;
        q[++tt]=i;
    }
    for(int i=mid+1;i<=r;i++){
        while(hh<tt && slope(q[hh],q[hh+1])<p[i].A/p[i].B+eps)
            hh++;
        int j=q[hh];
        f[p[i].id]=max(f[p[i].id],f[p[j].id]*(p[i].A*p[j].R+p[i].B)/p[j].b);
    }
    solve(mid+1,r);
    for(int i=l,j=mid+1;i<=mid || j<=r;)
        if(i<=mid && p[i].x<=p[j].x || j>r)
            t[i+j-mid-1]=p[i],i++;
        else
            t[i+j-mid-1]=p[j],j++;
    for(int i=l;i<=r;i++)
        p[i]=t[i];
}

int main(){
    scanf("%d%d",&n,&s);
    for(int i=1;i<=n;i++){
        scanf("%lf%lf%lf",&p[i].A,&p[i].B,&p[i].R);
        p[i].a=p[i].A+p[i].B/p[i].R;
        p[i].b=p[i].A*p[i].R+p[i].B;
        p[i].id=i;
    }
    sort(p+1,p+n+1,cmp);
    f[0]=s;
    solve(1,n);
    printf("%.3lf",f[n]);
    return 0;
}
